def alpha_beta_pruning(tree, is_maximizing=True):
    nodes_evaluated = [0]

    def search(node, alpha, beta, maximizing):
        if not isinstance(node, list):
            nodes_evaluated[0] += 1
            return node

        if maximizing:
            value = float('-inf')
            for child in node:
                child_val = search(child, alpha, beta, False)
                value = max(value, child_val)
                alpha = max(alpha, value)
                if alpha >= beta:
                    break
            return value
        else:
            value = float('inf')
            for child in node:
                child_val = search(child, alpha, beta, True)
                value = min(value, child_val)
                beta = min(beta, value)
                if alpha >= beta:
                    break
            return value

    result = search(tree, float('-inf'), float('inf'), is_maximizing)
    return (result, nodes_evaluated[0])
